    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<int> result(n, -1);
        for (int i = 0; i < n; i++) {
            int prev = -1;
            result[i] = i;
            for (int j = 0; j < n; j++) {
                if (redEdges[i][j] != -1 && redEdges[i][j] != prev) {
                    prev = redEdges[i][j];
                    result[redEdges[i][j] = result[i];
                }
                if (blueEdges[i][j] != -1 && blueEdges[i][j] != prev) {
                    prev = blueEdges[i][j];
                    result[blueEdges[i][j] = result[i];
                }
            }
        }
    }
    return result;
}
